// test_cherry_pick.cpp - Cherry-pick and revert operations tests
// Tests for git_cherry_pick() and git_revert()
#include "test_harness.h"

// Path to fixture repository (source for copies)
static const wchar_t* CHERRY_TEST_FIXTURE_PATH = L"test\\fixtures\\test_repo";

// Path to current temp test repo (empty if none active)
static wchar_t g_cherry_test_repo[512] = {};

// Forward declarations from test_write.cpp
extern bool delete_directory_recursive(const wchar_t* path);
extern bool copy_directory_recursive(const wchar_t* src, const wchar_t* dst);

// Create fresh temp copy of fixture repo
static bool create_cherry_test_repo() {
    if (g_cherry_test_repo[0] != L'\0') {
        delete_directory_recursive(g_cherry_test_repo);
        g_cherry_test_repo[0] = L'\0';
    }

    wchar_t temp_base[512];
    DWORD len = GetTempPathW(512, temp_base);
    if (len == 0 || len >= 512) {
        return false;
    }

    wchar_t temp_path[512];
    wcscpy_s(temp_path, temp_base);
    wcscat_s(temp_path, L"GitSmarter_cherry_test_");

    LARGE_INTEGER counter;
    QueryPerformanceCounter(&counter);
    wchar_t suffix[32];
    swprintf_s(suffix, L"%llx", counter.QuadPart);
    wcscat_s(temp_path, suffix);

    if (!copy_directory_recursive(CHERRY_TEST_FIXTURE_PATH, temp_path)) {
        delete_directory_recursive(temp_path);
        return false;
    }

    wcscpy_s(g_cherry_test_repo, temp_path);
    return true;
}

static void cleanup_cherry_test_repo() {
    if (g_cherry_test_repo[0] != L'\0') {
        delete_directory_recursive(g_cherry_test_repo);
        g_cherry_test_repo[0] = L'\0';
    }
}

// ============================================================================
// Cherry-Pick Tests
// ============================================================================

TEST(cherry_pick_simple) {
    if (!create_cherry_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_cherry_test_repo)) {
        cleanup_cherry_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get parent commit (we'll reset to grandparent, then cherry-pick parent)
    GitCommit head = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &head));

    if (head.parent_sha[0] == '\0') {
        git_repo_close(&repo);
        cleanup_cherry_test_repo();
        TEST_SKIP("HEAD has no parent");
    }

    GitCommit parent = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, head.parent_sha, &parent));

    if (parent.parent_sha[0] == '\0') {
        git_repo_close(&repo);
        cleanup_cherry_test_repo();
        TEST_SKIP("Need at least 3 commits for cherry-pick test");
    }

    // Save the commit we want to cherry-pick (HEAD)
    char commit_to_pick[41];
    strcpy_s(commit_to_pick, repo.head_sha);

    // Reset to grandparent (HEAD~2)
    char error[256] = {};
    TEST_ASSERT_TRUE(git_reset(&repo, parent.parent_sha, ResetMode::Hard, error, sizeof(error)));
    TEST_ASSERT_TRUE(git_read_head(&repo));

    char before_pick_head[41];
    strcpy_s(before_pick_head, repo.head_sha);

    // Cherry-pick the original HEAD commit
    bool result = git_cherry_pick(&repo, commit_to_pick, error, sizeof(error));
    TEST_ASSERT_TRUE(result);

    // HEAD should have advanced (new commit created)
    TEST_ASSERT_TRUE(git_read_head(&repo));
    TEST_ASSERT_STRNE(repo.head_sha, before_pick_head);

    // New commit's parent should be our before_pick_head
    GitCommit new_commit = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &new_commit));
    TEST_ASSERT_STREQ(new_commit.parent_sha, before_pick_head);

    git_repo_close(&repo);
    cleanup_cherry_test_repo();
}

TEST(cherry_pick_root_commit_fails) {
    if (!create_cherry_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_cherry_test_repo)) {
        cleanup_cherry_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Find root commit (walk back until no parent)
    char current[41];
    strcpy_s(current, repo.head_sha);

    GitCommit commit = {};
    while (true) {
        TEST_ASSERT_TRUE(git_read_commit(&repo, current, &commit));
        if (commit.parent_sha[0] == '\0') {
            break; // Found root
        }
        strcpy_s(current, commit.parent_sha);
    }

    // Trying to cherry-pick root commit should fail
    char error[256] = {};
    bool result = git_cherry_pick(&repo, current, error, sizeof(error));
    TEST_ASSERT_FALSE(result);
    TEST_ASSERT_TRUE(strlen(error) > 0);
    TEST_ASSERT_TRUE(strstr(error, "parent") != nullptr || strstr(error, "root") != nullptr);

    git_repo_close(&repo);
    cleanup_cherry_test_repo();
}

