TEST(revert_simple) {
    if (!create_cherry_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_cherry_test_repo)) {
        cleanup_cherry_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    GitCommit head = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &head));

    if (head.parent_sha[0] == '\0') {
        git_repo_close(&repo);
        cleanup_cherry_test_repo();
        TEST_SKIP("HEAD has no parent");
    }

    char original_head[41];
    strcpy_s(original_head, repo.head_sha);

    // Revert HEAD
    char error[256] = {};
    bool result = git_revert(&repo, original_head, error, sizeof(error));
    TEST_ASSERT_TRUE(result);

    // HEAD should have advanced (revert commit created)
    TEST_ASSERT_TRUE(git_read_head(&repo));
    TEST_ASSERT_STRNE(repo.head_sha, original_head);

    // New commit's parent should be original HEAD
    GitCommit revert_commit = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &revert_commit));
    TEST_ASSERT_STREQ(revert_commit.parent_sha, original_head);

    // Message should mention "Revert"
    TEST_ASSERT_TRUE(strstr(revert_commit.message, "Revert") != nullptr);

    git_repo_close(&repo);
    cleanup_cherry_test_repo();
}

TEST(revert_creates_commit) {
    if (!create_cherry_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_cherry_test_repo)) {
        cleanup_cherry_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    GitCommit head = {};
    TEST_ASSERT_TRUE(git_read_commit(&repo, repo.head_sha, &head));

    if (head.parent_sha[0] == '\0') {
        git_repo_close(&repo);
        cleanup_cherry_test_repo();
        TEST_SKIP("HEAD has no parent");
    }

    // Count commits before
    int commits_before = 0;
    char current[41];
    strcpy_s(current, repo.head_sha);
    while (true) {
        GitCommit c = {};
        if (!git_read_commit(&repo, current, &c)) break;
        commits_before++;
        if (c.parent_sha[0] == '\0') break;
        strcpy_s(current, c.parent_sha);
    }

    // Revert HEAD
    char error[256] = {};
    TEST_ASSERT_TRUE(git_revert(&repo, repo.head_sha, error, sizeof(error)));
    TEST_ASSERT_TRUE(git_read_head(&repo));

    // Count commits after
    int commits_after = 0;
    strcpy_s(current, repo.head_sha);
    while (true) {
        GitCommit c = {};
        if (!git_read_commit(&repo, current, &c)) break;
        commits_after++;
        if (c.parent_sha[0] == '\0') break;
        strcpy_s(current, c.parent_sha);
    }

    // Should have one more commit
    TEST_ASSERT_EQ(commits_after, commits_before + 1);

    git_repo_close(&repo);
    cleanup_cherry_test_repo();
}

